<?php function productCard($p,$deal=false){ ?><article class="product-card" data-category="<?=$p['category']?>" data-occasion="<?=$p['occasion']?>" data-price="<?=$p['price']?>"><a href="?page=product&id=<?=$p['id']?>" class="product-img"><img src="<?=$p['image']?>" alt="<?=$p['name']?>"><?php if($deal): ?><span class="deal-tag">SAVE <?=round((1-$p['price']/$p['old'])*100)?>%</span><div class="freshness"><i></i> Best enjoyed in 2 days</div><?php else: ?><button class="heart">♡</button><?php endif; ?></a><div class="product-meta"><div><span><?=$p['category']?> · <?=$p['palette']?></span><h3><a href="?page=product&id=<?=$p['id']?>"><?=$p['name']?></a></h3></div><b><?php if($p['old']): ?><del><?=peso($p['old'])?></del> <?php endif; ?><?=peso($p['price'])?></b></div></article><?php } ?>
